        await event.save();

        // Notify Organizer
        await Notification.create({
            recipient: event.organization,
            title: `Evento rimosso`,
            message: `Il tuo evento "${event.title}" è stato rimosso dalla moderazione. Motivo: ${reason}`,
            url: `/dashboard`,
        });

