// --- EVENTS ---

app.get('/api/events', async (req, res) => {
    try {
        const { organization, public: isPublic } = req.query;
        let query = {};

        if (organization) {
            query.organization = organization;
            if (isPublic === 'true') {
                 query.$or = [
                    { status: 'active' },
                    { status: { $exists: false } }
                 ];

                 // APPLICA LA REGOLA DELLE 10:00 AM ANCHE PER PROFILI PUBBLICI
                 const now = new Date();
                 const visibilityCutoff = new Date();
                 visibilityCutoff.setHours(0, 0, 0, 0); 

                 if (now.getHours() < 10) {
                     visibilityCutoff.setDate(visibilityCutoff.getDate() - 1); 
                 }
                 query.date = { $gte: visibilityCutoff };

            } else {
                 query.$or = [
                    { status: { $in: ['active', 'archived', 'draft'] } },
                    { status: { $exists: false } }
                 ];
            }
        } else {
            query.$or = [
                { status: 'active' },
                { status: { $exists: false } }
            ];

            const now = new Date();
            const currentHour = now.getHours();

            const visibilityCutoff = new Date();
            visibilityCutoff.setHours(0, 0, 0, 0); 

            if (currentHour < 10) {
                visibilityCutoff.setDate(visibilityCutoff.getDate() - 1); 
            } 

            query.date = { $gte: visibilityCutoff };
        }

        const events = await Event.find(query).populate('organization', 'name _id');
        res.json(events);
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

