app.post('/api/events', authMiddleware, async (req, res) => {
    if (req.user.role !== 'associazione') return res.status(403).json({ error: "Only associations can create events" });

    try {
        const user = await User.findById(req.user.userId);

        if (!user.isVerified) {
            return res.status(403).json({ error: "Account not verified." });
        }

        if (req.body.price !== undefined) {
             req.body.price = Number(Number(req.body.price).toFixed(2));
        }

        let { 
            title, description, longDescription, image, date, time, 
            location, price, maxCapacity, category, prLists, status,
            requiresMatricola, requiresCorsoStudi, scanType
        } = req.body;

        if (price < 0) return res.status(400).json({ error: "Price cannot be negative" });
        if (maxCapacity <= 0) return res.status(400).json({ error: "Max capacity must be > 0" });

        const inputDate = new Date(date);
        const today = new Date();
        today.setHours(0,0,0,0);
        if (inputDate < today) return res.status(400).json({ error: "Event date cannot be in the past" });

        const newEvent = await Event.create({
            title, 
            description, 
            longDescription, 
            image, 
            date, 
            time, 
            location, 
            price, 
            maxCapacity, 
            category, 
            prLists,
            organization: req.user.userId,
            stripeAccountId: user.stripeAccountId,
            ticketsSold: 0,
            favoritesCount: 0,
            status: status || 'active',
            requiresMatricola: !!requiresMatricola,
            requiresCorsoStudi: !!requiresCorsoStudi,
            scanType: scanType || 'entry_only'
        });

        await newEvent.populate('organization', 'name _id');

        // --- NEW NOTIFICATION LOGIC (In-App + Web Push) ---
        if (newEvent.status === 'active') {
             const followers = await User.find({ followedAssociations: req.user.userId });

             if (followers.length > 0) {
                 const notificationDocs = followers.map(follower => ({
                     recipient: follower._id,
                     title: `Nuovo Evento: ${newEvent.title}`,
                     message: `${user.name} ha pubblicato un nuovo evento!`,
                     url: `/events/${newEvent._id}`,
                     isRead: false,
                     relatedEvent: newEvent._id 
                 }));

                 await Notification.insertMany(notificationDocs);

                 const payload = {
                     title: `Nuovo Evento: ${newEvent.title}`,
                     body: `${user.name} ha pubblicato un nuovo evento!`,
                     url: `/events/${newEvent._id}`,
                     icon: '/icon-192x192.png' 
                 };

                 followers.forEach(follower => {
                     if (follower.pushSubscription && follower.pushSubscription.endpoint) {
                         webPushConfig.sendPushNotification(follower.pushSubscription, payload);
                     }
                 });
             }
        }

        res.json(newEvent);
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

