                                                    <Users className="w-3 h-3 mr-1" />
                                                    Lista
                                                </Link>
                                                <Link 
                                                    to={`/events/${event._id}`} 
                                                    className="px-3 py-1.5 bg-indigo-50 hover:bg-indigo-100 text-indigo-700 rounded-lg text-xs font-bold transition"
